// SPDX-License-Identifier: MIT 
pragma solidity >=0.8.2 <0.9.0;

contract test{
    mapping(bytes32=>bool) hashExists;

    function storeHash(bytes32 hashValue) public{
        require(!hashExists[hashValue],"Hash already stored");
        hashExists[hashValue] = true;
    }

    function verifyHash(bytes32 id) public view returns(bool){
        return hashExists[id];
    }
}

